65	    expect(
66	      quote({
67	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
68	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
69	      })
70	    ).toBe(71);
71	  });
72	  it("4 runes yield base premium 100 G (block requires exactly 3)", () => {
73	    expect(
74	      quote({
75	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
76	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
77	      })
78	    ).toBe(115);
79	  });
80	  it("7 runes yield base premium 175 G (no block)", () => {
81	    expect(
82	      quote({
83	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
84	        items: [
85	          { type: "rune" },
86	          { type: "rune" },
87	          { type: "rune" },
88	          { type: "rune" },
89	          { type: "rune" },
90	          { type: "rune" },
91	          { type: "rune" },
92	        ],
93	      })
94	    ).toBe(198);
95	  });
96	  it("2 runes + 1 moonstone yield base premium 75 G (different types, no block)", () => {
97	    expect(
98	      quote({
99	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
100	        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
101	      })
102	    ).toBe(88);
103	  });
104	  it("3 runes + 3 moonstones yield base premium 120 G (two separate blocks)", () => {
105	    expect(
106	      quote({
107	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
108	        items: [
109	          { type: "rune" },
110	          { type: "rune" },
111	          { type: "rune" },
112	          { type: "moonstone" },
113	          { type: "moonstone" },
114	          { type: "moonstone" },
115	        ],
116	      })
117	    ).toBe(137);
118	  });
119	
120	  // ===== Quote: item-specific modifiers =====
121	  it("cursed sword adds 50% surcharge on item base (cursed sword alone: 100 + 50 = 150 base)", () => {
122	    expect(
123	      quote({
124	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
125	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }],
126	      })
127	    ).toBe(165);
128	  });
129	  it("highly enchanted sword (enchantment 5) adds 30% surcharge on item base", () => {
130	    expect(
131	      quote({
132	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
133	        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
134	      })
135	    ).toBe(145);
136	  });
137	  it("sword with enchantment 4 has no high-enchantment surcharge", () => {
138	    expect(
139	      quote({
140	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
141	        items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
142	      })
143	    ).toBe(115);
144	  });
145	  it("cursed sword with enchantment 5 stacks both surcharges on item base", () => {
146	    expect(
147	      quote({
148	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
149	        items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
150	      })
151	    ).toBe(195);
152	  });
153	
154	  // ===== Quote: modifier scope on multi-item policies =====
155	  it("policy with cursed sword + plain amulet: cursed surcharge applies only to cursed item base (newcomer total 231 G)", () => {
156	    expect(
157	      quote({
158	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
159	        items: [
160	          { type: "sword", material: "steel", enchantment: 0, cursed: true },
161	          { type: "amulet" },
162	        ],
163	      })
164	    ).toBe(231);
165	  });
166	
167	  // ===== Quote: policy-wide modifiers =====
168	  it("long-standing customer (exactly 2 years) receives 20% loyalty discount on policy base", () => {
169	    expect(
170	      quote({
171	        customer: { yearsWithMHPCO: 2, previousContracts: 0 },
172	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
173	      })
174	    ).toBe(95);
175	  });
176	  it.todo("first insurance (newcomer, no prior contracts) adds 10% surcharge on policy base");
177	  it.todo("follow-up contract gives 15% discount on policy base");
178	
179	  // ===== Quote: rounding in MHPCO's favor =====
180	  it.todo("premium calculation that yields 197.5 G rounds up to 198 G");
181	  it.todo("intermediate amounts kept as fractions; only final premium is rounded");
182	
183	  // ===== Quote: integration examples from spec =====
184	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields premium 165 G");
185	  it.todo("long-standing (3 yrs) customer's second quote with cursed sword (enchantment 7) yields premium 160 G");
186	
187	  // ===== Claim: basic deductible =====
188	  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G (full minus 100 deductible)");
189	  it.todo("rune (insurance value 250 G), damage 200 G yields payout 100 G (full minus deductible, no special clauses)");
190	
191	  // ===== Claim: special clauses =====
192	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
193	  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
194	  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible — both clauses apply)");
195	  it.todo("dragon-material sword exactly enchantment 8, damage 1000 G yields payout 400 G (50% then deductible)");
196	
197	  // ===== Claim: deductible per damage event (multi-item incident) =====
198	  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G (deductible per item)");
199	
200	  // ===== Claim: rounding =====
201	  it.todo("payout calculation that yields 350.5 G rounds down to 350 G");
202	
203	  // ===== Claim: insurance sum and cap =====
204	  it.todo("policy of sword + amulet: insurance sum 1600 G, cap 3200 G");
205	  it.todo("policy of sword + 3 runes (a block): insurance sum 1750 G (block discount affects premium only)");
206	  it.todo("cursed sword: cap 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
207	
208	  // ===== Claim: cap exhaustion across successive claims =====
209	  it.todo("sword (cap 2000 G), first claim 1500 G yields payout 1400 G, remainingCap 600 G");
210	  it.todo("sword (cap 2000 G), after first 1500 G claim, second 1500 G claim yields payout 600 G, remainingCap 0 G");
211	
212	  // ===== Claim: multiple items of same type =====
213	  it.todo("policy covers two swords: insurance sum 2000 G, cap 4000 G");
214	  it.todo("dragon attack damages both insured swords: each entry treated separately with own deductible");
215	
216	  // ===== CLI / scenario integration =====
217	  it.todo("scenario with quote then claim returns results array of length 2 with {premium} and {payout, remainingCap}");
218	
219	  // ===== Error cases =====
220	  it.todo("quote with unknown item type (e.g. broomstick) causes CLI to exit non-zero with stderr error");
221	  it.todo("claim referencing damage to an item not in the policy causes CLI to exit non-zero with stderr error");
222	  it.todo("claim with damages array containing more entries of a type than insured causes CLI to exit non-zero");
223	  it.todo("claim with negative damage amount causes CLI to exit non-zero with stderr error");
224	});
