3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	const LOYALTY_YEARS_THRESHOLD = 2;
24	const CURSED_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	const COMPONENT_BASE = 25;
28	const COMPONENT_BLOCK_PREMIUM = 60;
29	
30	const ITEM_BASE_PREMIUMS: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: 25,
36	  moonstone: 25,
37	};
38	
39	function isComponentType(type: string): boolean {
40	  return ITEM_BASE_PREMIUMS[type] === COMPONENT_BASE;
41	}
42	
43	function groupItemsByType(items: Item[]): Map<string, Item[]> {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const group = groups.get(item.type) ?? [];
47	    group.push(item);
48	    groups.set(item.type, group);
49	  }
50	  return groups;
51	}
52	
53	function totalSurchargeRate(item: Item): number {
54	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
55	  const highEnchantmentRate =
56	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
57	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
58	      : 0;
59	  return cursedRate + highEnchantmentRate;
60	}
61	
62	function calculateItemSurcharge(type: string, item: Item): number {
63	  const base = ITEM_BASE_PREMIUMS[type];
64	  return base * totalSurchargeRate(item);
65	}
66	
67	function calculateGroupBase(type: string, group: Item[]): number {
68	  if (isComponentType(type) && group.length === 3) {
69	    return COMPONENT_BLOCK_PREMIUM;
70	  }
71	  return group.reduce((sum) => sum + ITEM_BASE_PREMIUMS[type], 0);
72	}
73	
74	function calculatePolicyBase(items: Item[]): number {
75	  const groups = groupItemsByType(items);
76	  return Array.from(groups).reduce(
77	    (total, [type, group]) => total + calculateGroupBase(type, group),
78	    0
79	  );
80	}
81	
82	function calculateItemSurcharges(items: Item[]): number {
83	  return items.reduce(
84	    (total, item) => total + calculateItemSurcharge(item.type, item),
85	    0
86	  );
87	}
88	
89	function calculateLoyaltyDiscount(customer: Customer, policyBase: number): number {
90	  if (customer.yearsWithMHPCO < LOYALTY_YEARS_THRESHOLD) {
91	    return 0;
92	  }
93	  return policyBase * LOYALTY_DISCOUNT_RATE;
94	}
95	
96	export function quote(input: QuoteInput): number {
97	  const policyBase = calculatePolicyBase(input.items);
98	  const itemSurcharges = calculateItemSurcharges(input.items);
99	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
100	  const loyaltyDiscount = calculateLoyaltyDiscount(input.customer, policyBase);
101	  return Math.ceil(
102	    policyBase + itemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE - loyaltyDiscount
103	  );
104	}
